reporters: ['basic'], // Minimal outputname: Deploy (manual only)
on:
  workflow_dispatch:
    inputs:
      environment:
        description: 'Deployment environment'
        required: true
        default: 'staging'
        type: choice
        options:
          - staging
          - production
env:
  CARGO_TERM_COLOR: always
jobs:
  deploy-docs:
    name: Deploy Documentation
    runs-on: ubuntu-latest
    if: github.ref == 'refs/heads/main'
    steps:
    - name: Checkout code
      uses: actions/checkout@v4
    - name: Install Rust toolchain
      uses: dtolnay/rust-toolchain@stable
    - name: Install mdBook
      run: |
        curl -L https://github.com/rust-lang/mdBook/releases/latest/download/mdbook-x86_64-unknown-linux-gnu.tar.gz | tar xz
        sudo mv mdbook /usr/local/bin/
    - name: Generate Rust documentation
      working-directory: ./src-tauri
      run: |
        cargo doc --no-deps --all-features --document-private-items
    - name: Create documentation site
      run: |
        mkdir -p docs-site/api
        mkdir -p docs-site/guide
        # Copy generated Rust docs
        cp -r src-tauri/target/doc/* docs-site/api/ || echo "No Rust docs to copy"
        # Copy markdown documentation
        cp README.md docs-site/
        cp API.md docs-site/guide/
        cp DEVELOPMENT.md docs-site/guide/
        # Create index.html
        cat > docs-site/index.html << 'EOF'
        <!DOCTYPE html>
        <html>
        <head>
            <title>StratoRust Documentation</title>
            <style>
                body { font-family: Arial, sans-serif; margin: 40px; }
                .container { max-width: 800px; margin: 0 auto; }
                .section { margin: 20px 0; padding: 20px; border: 1px solid #ddd; border-radius: 8px; }
                .section h2 { margin-top: 0; }
                .links a { display: block; margin: 10px 0; padding: 10px; background: #f5f5f5; text-decoration: none; border-radius: 4px; }
                .links a:hover { background: #e5e5e5; }
            </style>
        </head>
        <body>
            <div class="container">
                <h1>StratoRust Documentation</h1>
                <div class="section">
                    <h2>User Guide</h2>
                    <div class="links">
                        <a href="README.html">Overview & Getting Started</a>
                        <a href="guide/API.html">API Documentation</a>
                        <a href="guide/DEVELOPMENT.html">Development Guide</a>
                    </div>
                </div>
                <div class="section">
                    <h2>API Reference</h2>
                    <div class="links">
                        <a href="api/stratosort/index.html">Rust API Documentation</a>
                    </div>
                </div>
                <div class="section">
                    <h2>Links</h2>
                    <div class="links">
                        <a href="https://github.com/your-username/StratoRust">GitHub Repository</a>
                        <a href="https://github.com/your-username/StratoRust/releases">Download Releases</a>
                        <a href="https://github.com/your-username/StratoRust/issues">Report Issues</a>
                    </div>
                </div>
            </div>
        </body>
        </html>
        EOF
    - name: Convert Markdown to HTML
      run: |
        # Simple markdown to HTML conversion
        for file in docs-site/*.md docs-site/guide/*.md; do
          if [ -f "$file" ]; then
            html_file="${file%.md}.html"
            echo "<!DOCTYPE html><html><head><title>$(basename "$file" .md)</title><style>body{font-family:Arial,sans-serif;margin:40px;max-width:800px;margin:0 auto;padding:20px;}</style></head><body>" > "$html_file"
            # Basic markdown processing (would use proper tool in production)
            sed 's/^# \(.*\)/<h1>\1<\/h1>/g; s/^## \(.*\)/<h2>\1<\/h2>/g; s/^### \(.*\)/<h3>\1<\/h3>/g; s/^\*\*\(.*\)\*\*/<strong>\1<\/strong>/g; s/^\*\(.*\)\*/<em>\1<\/em>/g' "$file" >> "$html_file"
            echo "</body></html>" >> "$html_file"
            rm "$file"
          fi
        done
    - name: Deploy to GitHub Pages
      uses: peaceiris/actions-gh-pages@v3
      with:
        github_token: ${{ secrets.GITHUB_TOKEN }}
        publish_dir: ./docs-site
        force_orphan: true
  deploy-staging:
    name: Deploy to Staging
    runs-on: ubuntu-latest
    if: github.ref == 'refs/heads/main' || (github.event_name == 'workflow_dispatch' && github.event.inputs.environment == 'staging')
    environment: staging
    steps:
    - name: Checkout code
      uses: actions/checkout@v4
    - name: Install Rust toolchain
      uses: dtolnay/rust-toolchain@stable
    - name: Install system dependencies
      run: |
        sudo apt-get update
        sudo apt-get install -y libgtk-3-dev libwebkit2gtk-4.0-dev libayatana-appindicator3-dev librsvg2-dev
    - name: Install Tauri CLI
      run: cargo install tauri-cli --version "^2.0"
    - name: Setup Node.js
      uses: actions/setup-node@v4
      with:
        node-version: '18'
    - name: Create staging build
      env:
        DATABASE_URL: sqlite:./data/stratosort_staging.db
        RUST_LOG: info
      run: |
        mkdir -p data
        cargo tauri build --debug
    - name: Deploy to staging server
      env:
        STAGING_HOST: ${{ secrets.STAGING_HOST }}
        STAGING_USER: ${{ secrets.STAGING_USER }}
        STAGING_KEY: ${{ secrets.STAGING_SSH_KEY }}
      run: |
