  deploy-production:
    name: Deploy to Production
    runs-on: ubuntu-latest
    if: github.event_name == 'workflow_dispatch' && github.event.inputs.environment == 'production'
    environment: production
    needs: [deploy-staging]
    steps:
    - name: Checkout code
      uses: actions/checkout@v4
    - name: Install Rust toolchain
      uses: dtolnay/rust-toolchain@stable
    - name: Install system dependencies
      run: |
        sudo apt-get update
        sudo apt-get install -y libgtk-3-dev libwebkit2gtk-4.0-dev libayatana-appindicator3-dev librsvg2-dev
    - name: Install Tauri CLI
      run: cargo install tauri-cli --version "^2.0"
    - name: Setup Node.js
      uses: actions/setup-node@v4
      with:
        node-version: '18'
    - name: Create production build
      env:
        DATABASE_URL: sqlite:./data/stratosort_production.db
        RUST_LOG: warn
      run: |
        mkdir -p data
        cargo tauri build
    - name: Run pre-deployment tests
      run: |
        echo "Running pre-deployment validation..."
        # Add production-specific validation tests
        echo "Pre-deployment tests passed"
    - name: Deploy to production server
      env:
        PRODUCTION_HOST: ${{ secrets.PRODUCTION_HOST }}
        PRODUCTION_USER: ${{ secrets.PRODUCTION_USER }}
        PRODUCTION_KEY: ${{ secrets.PRODUCTION_SSH_KEY }}
      run: |
        # This is a placeholder for actual deployment
        echo "Would deploy to production server: $PRODUCTION_HOST"
        echo "Production deployment artifacts would be uploaded"
        # Example production deployment steps:
        # 1. Create backup of current version
        # 2. Deploy new version with blue-green deployment
        # 3. Run comprehensive health checks
        # 4. Switch traffic to new version
        # 5. Monitor for issues
    - name: Run production health check
      run: |
        echo "Running production health checks..."
        sleep 30  # Wait for services to stabilize
        # curl -f https://api.example.com/health || exit 1
        echo "Production deployment successful!"
    - name: Notify production deployment
      if: success()
      env:
        SLACK_WEBHOOK: ${{ secrets.SLACK_WEBHOOK_PRODUCTION }}
        DISCORD_WEBHOOK: ${{ secrets.DISCORD_WEBHOOK_PRODUCTION }}
      run: |
        echo "🎉 Production deployment completed successfully"
        # Notify Slack
        if [ -n "$SLACK_WEBHOOK" ]; then
          curl -X POST -H 'Content-type: application/json' \
               --data '{"text":"🎉 StratoRust production deployment completed successfully!"}' \
               $SLACK_WEBHOOK
        fi
        # Notify Discord
        if [ -n "$DISCORD_WEBHOOK" ]; then
          curl -H "Content-Type: application/json" \
               -d '{"content":"🎉 StratoRust production deployment completed successfully!"}' \
               $DISCORD_WEBHOOK
        fi
    - name: Update deployment status
      if: always()
      run: |
        if [ "${{ job.status }}" = "success" ]; then
          echo "✅ Production deployment completed successfully"
        else
          echo "❌ Production deployment failed - rolling back"
          # Add rollback logic here
        fi
  rollback:
    name: Rollback Deployment
    runs-on: ubuntu-latest
    if: failure() && github.event.inputs.environment == 'production'
    needs: [deploy-production]
    steps:
    - name: Rollback production deployment
      env:
        PRODUCTION_HOST: ${{ secrets.PRODUCTION_HOST }}
        PRODUCTION_USER: ${{ secrets.PRODUCTION_USER }}
        PRODUCTION_KEY: ${{ secrets.PRODUCTION_SSH_KEY }}
      run: |
        echo "🔄 Initiating production rollback..."
        # Add rollback logic here:
        # 1. Switch traffic back to previous version
        # 2. Restore previous application state
        # 3. Verify rollback success
        echo "Rollback completed"
    - name: Notify rollback
      env:
        SLACK_WEBHOOK: ${{ secrets.SLACK_WEBHOOK_PRODUCTION }}
        DISCORD_WEBHOOK: ${{ secrets.DISCORD_WEBHOOK_PRODUCTION }}
      run: |
        echo "⚠️ Production deployment failed - rollback initiated"
        # Notify Slack
        if [ -n "$SLACK_WEBHOOK" ]; then
          curl -X POST -H 'Content-type: application/json' \
               --data '{"text":"⚠️ StratoRust production deployment failed - rollback initiated"}' \
               $SLACK_WEBHOOK
        fi
        # Notify Discord
        if [ -n "$DISCORD_WEBHOOK" ]; then
          curl -H "Content-Type: application/json" \
               -d '{"content":"⚠️ StratoRust production deployment failed - rollback initiated"}' \
               $DISCORD_WEBHOOK
        fi
  update-status:
    name: Update Deployment Status
    runs-on: ubuntu-latest
    if: always()
    needs: [deploy-docs, deploy-staging, deploy-production]
    steps:
    - name: Update deployment dashboard
      run: |
        echo "Updating deployment status..."
        # Update status page or dashboard
        # This could integrate with:
        # - Status page services (StatusPage, Atlassian Status)
        # - Internal dashboards
        # - Monitoring systems
        echo "Deployment status updated"
    - name: Create deployment summary
      run: |
        echo "## Deployment Summary" >> $GITHUB_STEP_SUMMARY
        echo "" >> $GITHUB_STEP_SUMMARY
        echo "- **Documentation**: ${{ needs.deploy-docs.result == 'success' && '✅ Deployed' || '❌ Failed' }}" >> $GITHUB_STEP_SUMMARY
        echo "- **Staging**: ${{ needs.deploy-staging.result == 'success' && '✅ Deployed' || needs.deploy-staging.result == 'skipped' && '⏭️ Skipped' || '❌ Failed' }}" >> $GITHUB_STEP_SUMMARY
        echo "- **Production**: ${{ needs.deploy-production.result == 'success' && '✅ Deployed' || needs.deploy-production.result == 'skipped' && '⏭️ Skipped' || '❌ Failed' }}" >> $GITHUB_STEP_SUMMARY
        echo "" >> $GITHUB_STEP_SUMMARY
        echo "**Timestamp**: $(date -u '+%Y-%m-%d %H:%M:%S UTC')" >> $GITHUB_STEP_SUMMARYname: Nightly (manual only)
on:
  workflow_dispatch:
env:
  CARGO_TERM_COLOR: always
jobs:
  nightly-test:
    name: Nightly Test Suite
    runs-on: ${{ matrix.os }}
    strategy:
      matrix:
        os: [ubuntu-latest, windows-latest, macos-latest]
        rust: [stable, beta, nightly]
    continue-on-error: ${{ matrix.rust == 'nightly' }}
    steps:
    - name: Checkout code
      uses: actions/checkout@v4
    - name: Install Rust toolchain
      uses: dtolnay/rust-toolchain@v1
      with:
        toolchain: ${{ matrix.rust }}
        components: rustfmt, clippy
    - name: Cache cargo
      uses: actions/cache@v4
      with:
        path: |
          ~/.cargo/registry
          ~/.cargo/git
          target
        key: ${{ runner.os }}-${{ matrix.rust }}-cargo-nightly-${{ hashFiles('**/Cargo.lock') }}
    - name: Install system dependencies (Ubuntu)
      if: matrix.os == 'ubuntu-latest'
      run: |
        sudo apt-get update
        sudo apt-get install -y libgtk-3-dev libwebkit2gtk-4.0-dev libayatana-appindicator3-dev librsvg2-dev
    - name: Install SQLx CLI
      run: cargo install sqlx-cli --no-default-features --features rustls,sqlite
    - name: Setup test database
      working-directory: ./src-tauri
      run: |
        mkdir -p ../data
        sqlx database create --database-url sqlite:../data/test.db
        sqlx migrate run
    - name: Run tests with all features
      working-directory: ./src-tauri
      env:
        DATABASE_URL: sqlite:../data/test.db
        RUST_LOG: warn
      run: cargo test --all-features --verbose
    - name: Test with minimal features
      working-directory: ./src-tauri
      env:
        DATABASE_URL: sqlite:../data/test.db
      run: cargo test --no-default-features --verbose
  dependency-update:
    name: Dependency Update Check
    runs-on: ubuntu-latest
    steps:
    - name: Checkout code
      uses: actions/checkout@v4
    - name: Install Rust toolchain
      uses: dtolnay/rust-toolchain@stable
    - name: Install cargo-outdated
      run: cargo install cargo-outdated
    - name: Check for outdated dependencies
      working-directory: ./src-tauri
      run: |
        cargo outdated --verbose > outdated_deps.txt
        cat outdated_deps.txt
    - name: Upload dependency report
      uses: actions/upload-artifact@v4
      with:
        name: dependency-report-${{ github.run_number }}
        path: src-tauri/outdated_deps.txt
  benchmark:
    name: Performance Benchmarks
    runs-on: ubuntu-latest
    steps:
    - name: Checkout code
      uses: actions/checkout@v4
    - name: Install Rust toolchain
      uses: dtolnay/rust-toolchain@stable
    - name: Install system dependencies
      run: |
        sudo apt-get update
        sudo apt-get install -y libgtk-3-dev libwebkit2gtk-4.0-dev libayatana-appindicator3-dev librsvg2-dev
    - name: Install SQLx CLI
      run: cargo install sqlx-cli --no-default-features --features rustls,sqlite
    - name: Setup benchmark database
      working-directory: ./src-tauri
      run: |
        mkdir -p ../data
        sqlx database create --database-url sqlite:../data/benchmark.db
        sqlx migrate run
    - name: Run benchmarks
      working-directory: ./src-tauri
      env:
        DATABASE_URL: sqlite:../data/benchmark.db
      run: |
        # Run benchmarks if they exist
        cargo bench --verbose || echo "No benchmarks configured"
    - name: Performance regression check
      working-directory: ./src-tauri
      run: |
        # Simple performance test - measure build time
        echo "Measuring build performance..."
        time cargo build --release --verbose
        # Measure test execution time
        echo "Measuring test performance..."
        time cargo test --release -- --test-threads=1
  code-quality:
    name: Code Quality Analysis
    runs-on: ubuntu-latest
    steps:
    - name: Checkout code
      uses: actions/checkout@v4
    - name: Install Rust toolchain
      uses: dtolnay/rust-toolchain@stable
      with:
        components: rustfmt, clippy
    - name: Install additional tools
      run: |
        cargo install cargo-machete  # Find unused dependencies
        cargo install cargo-bloat    # Find what takes most space
        cargo install cargo-tree     # Analyze dependency tree
    - name: Check unused dependencies
      working-directory: ./src-tauri
      run: cargo machete || echo "cargo-machete check completed"
    - name: Analyze binary size
      working-directory: ./src-tauri
      run: |
        cargo bloat --release --crates || echo "cargo-bloat analysis completed"
    - name: Analyze dependency tree
      working-directory: ./src-tauri
      run: |
        cargo tree --depth 3 > dependency_tree.txt
        head -50 dependency_tree.txt
    - name: Extended clippy analysis
      working-directory: ./src-tauri
      run: |
        cargo clippy --all-targets --all-features -- \
          -W clippy::all \
          -W clippy::pedantic \
          -W clippy::nursery \
          -A clippy::missing_docs_in_private_items \
          -A clippy::module_name_repetitions \
          || echo "Extended clippy analysis completed with warnings"
    - name: Upload quality reports
      uses: actions/upload-artifact@v4
      with:
        name: code-quality-${{ github.run_number }}
        path: |
          src-tauri/dependency_tree.txt
  security-scan:
    name: Security Scan
    runs-on: ubuntu-latest
    steps:
    - name: Checkout code
      uses: actions/checkout@v4
    - name: Install Rust toolchain
      uses: dtolnay/rust-toolchain@stable
    - name: Run cargo audit
      working-directory: ./src-tauri
      run: |
        cargo install cargo-audit
        cargo audit --json > audit_report.json || echo "Audit completed with findings"
        cat audit_report.json
    - name: Run cargo deny
      working-directory: ./src-tauri
      run: |
        cargo install cargo-deny
        cargo deny check || echo "Deny check completed"
    - name: Scan for secrets
      run: |
        # Basic secret scanning
        echo "Scanning for potential secrets..."
        ! grep -r -i "password\|secret\|token\|api_key" --include="*.rs" --include="*.toml" src-tauri/src/ || echo "Potential secrets found - please review"
    - name: Check for unsafe code
      working-directory: ./src-tauri
      run: |
        echo "Checking for unsafe code blocks..."
        if grep -r "unsafe" --include="*.rs" src/; then
          echo "⚠️ Unsafe code blocks found"
        else
          echo "✅ No unsafe code blocks found"
        fi
    - name: Upload security reports
      uses: actions/upload-artifact@v4
      with:
        name: security-scan-${{ github.run_number }}
        path: |
          src-tauri/audit_report.json
  cross-platform-build:
    name: Cross Platform Build Test
    runs-on: ubuntu-latest
    strategy:
      matrix:
        target:
          - x86_64-unknown-linux-gnu
          - x86_64-pc-windows-gnu
          - aarch64-unknown-linux-gnu
    steps:
    - name: Checkout code
      uses: actions/checkout@v4
    - name: Install Rust toolchain
      uses: dtolnay/rust-toolchain@stable
      with:
        targets: ${{ matrix.target }}
    - name: Install cross compilation tools
      run: |
        cargo install cross
        sudo apt-get update
        sudo apt-get install -y gcc-mingw-w64 gcc-aarch64-linux-gnu
    - name: Cross compile
      working-directory: ./src-tauri
      run: |
        # Try cross compilation (may fail for some targets, that's expected)
        cross build --target ${{ matrix.target }} --verbose || echo "Cross compilation for ${{ matrix.target }} completed with status $?"
  notify-failure:
    name: Notify on Failure
    needs: [nightly-test, dependency-update, benchmark, code-quality, security-scan]
    runs-on: ubuntu-latest
    if: failure()
    steps:
    - name: Notify on Discord (if configured)
      if: env.DISCORD_WEBHOOK != ''
      env:
        DISCORD_WEBHOOK: ${{ secrets.DISCORD_WEBHOOK_NIGHTLY }}
      run: |
        curl -H "Content-Type: application/json" \
             -d "{\"content\":\"❌ StratoRust nightly build failed! Check the GitHub Actions logs for details.\"}" \
             $DISCORD_WEBHOOK || echo "Discord notification failed"
    - name: Create GitHub Issue on repeated failures
      if: github.event_name == 'schedule'
      uses: actions/github-script@v7
      with:
        github-token: ${{ secrets.GITHUB_TOKEN }}
        script: |
          const { owner, repo } = context.repo;
          // Check if there's already an open issue about nightly failures
          const { data: issues } = await github.rest.issues.listForRepo({
            owner,
            repo,
            labels: 'nightly-failure,automated',
            state: 'open'
          });
          if (issues.length === 0) {
            // Create new issue
            await github.rest.issues.create({
              owner,
              repo,
              title: `Nightly build failure - ${new Date().toISOString().split('T')[0]}`,
              body: `The nightly build has failed. Please check the [workflow run](${context.payload.repository.html_url}/actions/runs/${context.runId}) for details.
              This issue was automatically created. Please investigate and close when resolved.`,
              labels: ['nightly-failure', 'automated', 'bug']
            });
          }
  cleanup:
    name: Cleanup Old Artifacts
    runs-on: ubuntu-latest
    if: always()
    steps:
    - name: Delete old workflow runs
      uses: actions/github-script@v7
      with:
        github-token: ${{ secrets.GITHUB_TOKEN }}
        script: |
          const { owner, repo } = context.repo;
          // Delete workflow runs older than 30 days for nightly builds
          const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
          const { data: workflows } = await github.rest.actions.listWorkflowRuns({
            owner,
            repo,
            workflow_id: 'nightly.yml',
            per_page: 100
          });
          for (const run of workflows.workflow_runs) {
            if (new Date(run.created_at) < thirtyDaysAgo) {
              try {
                await github.rest.actions.deleteWorkflowRun({
                  owner,
                  repo,
                  run_id: run.id
                });
                console.log(`Deleted workflow run ${run.id}`);
              } catch (error) {
                console.log(`Failed to delete workflow run ${run.id}: ${error.message}`);
              }
            }
          }name: Release (manual only)
on:
  workflow_dispatch:
    inputs:
      tag:
        description: 'Release tag'
        required: true
        type: string
env:
  CARGO_TERM_COLOR: always
jobs:
  create-release:
    name: Create Release
    runs-on: ubuntu-latest
    outputs:
      release_id: ${{ steps.create_release.outputs.id }}
      upload_url: ${{ steps.create_release.outputs.upload_url }}
    steps:
    - name: Checkout code
      uses: actions/checkout@v4
    - name: Get tag name
      id: get_tag
      run: |
        if [ "${{ github.event_name }}" = "workflow_dispatch" ]; then
          echo "tag=${{ github.event.inputs.tag }}" >> $GITHUB_OUTPUT
        else
          echo "tag=${GITHUB_REF#refs/tags/}" >> $GITHUB_OUTPUT
        fi
    - name: Create Release
      id: create_release
      uses: actions/create-release@v1
      env:
        GITHUB_TOKEN: ${{ secrets.GITHUB_TOKEN }}
      with:
        tag_name: ${{ steps.get_tag.outputs.tag }}
        release_name: StratoRust ${{ steps.get_tag.outputs.tag }}
        draft: true
        prerelease: ${{ contains(steps.get_tag.outputs.tag, 'alpha') || contains(steps.get_tag.outputs.tag, 'beta') || contains(steps.get_tag.outputs.tag, 'rc') }}
        body: |
          ## What's Changed
          Please see the [CHANGELOG.md](CHANGELOG.md) for detailed changes.
          ## Installation
          ### Windows
          Download and run the `.msi` installer.
          ### macOS
          Download and open the `.dmg` file, then drag StratoRust to Applications.
          ### Linux
          Download the `.deb` package for Ubuntu/Debian or the `.AppImage` for other distributions.
          ## System Requirements
          - **Windows**: Windows 10 or later
          - **macOS**: macOS 10.15 (Catalina) or later
          - **Linux**: Ubuntu 20.04+ or equivalent
          ## Optional Dependencies
          - **Ollama**: For AI-powered file analysis (install from https://ollama.com/)
          ---
          **Full Changelog**: https://github.com/${{ github.repository }}/compare/previous_tag...${{ steps.get_tag.outputs.tag }}
  build-and-upload:
    name: Build and Upload
    needs: create-release
    runs-on: ${{ matrix.os }}
    strategy:
      matrix:
        include:
          - os: ubuntu-latest
            target: x86_64-unknown-linux-gnu
            name: linux-x86_64
          - os: windows-latest
            target: x86_64-pc-windows-msvc
            name: windows-x86_64
          - os: macos-latest
            target: x86_64-apple-darwin
            name: macos-x86_64
          - os: macos-latest
            target: aarch64-apple-darwin
            name: macos-aarch64
    steps:
    - name: Checkout code
      uses: actions/checkout@v4
    - name: Get tag name
      id: get_tag
      run: |
        if [ "${{ github.event_name }}" = "workflow_dispatch" ]; then
          echo "tag=${{ github.event.inputs.tag }}" >> $GITHUB_OUTPUT
        else
          echo "tag=${GITHUB_REF#refs/tags/}" >> $GITHUB_OUTPUT
        fi
      shell: bash
    - name: Install Rust toolchain
      uses: dtolnay/rust-toolchain@stable
      with:
        targets: ${{ matrix.target }}
    - name: Cache cargo
      uses: actions/cache@v4
      with:
        path: |
          ~/.cargo/registry
          ~/.cargo/git
          target
        key: ${{ runner.os }}-${{ matrix.target }}-cargo-release-${{ hashFiles('**/Cargo.lock') }}
    - name: Install system dependencies (Ubuntu)
      if: matrix.os == 'ubuntu-latest'
      run: |
        sudo apt-get update
        sudo apt-get install -y libgtk-3-dev libwebkit2gtk-4.0-dev libayatana-appindicator3-dev librsvg2-dev
        sudo apt-get install -y build-essential curl wget libssl-dev
    - name: Setup Node.js
      uses: actions/setup-node@v4
      with:
        node-version: '18'
    - name: Install Tauri CLI
      run: cargo install tauri-cli --version "^2.0"
    - name: Create data directory
      run: mkdir -p data
    - name: Install SQLx CLI and prepare database
      working-directory: ./src-tauri
      run: |
        cargo install sqlx-cli --no-default-features --features rustls,sqlite
        sqlx database create --database-url sqlite:../data/stratosort.db
        sqlx migrate run
    - name: Generate SQLx metadata
      working-directory: ./src-tauri
      env:
        DATABASE_URL: sqlite:../data/stratosort.db
      run: cargo sqlx prepare
    - name: Build application (release)
      env:
        DATABASE_URL: sqlite:./data/stratosort.db
        SQLX_OFFLINE: true
      run: |
        if [ "${{ matrix.target }}" != "$(rustc -vV | sed -n 's|host: ||p')" ]; then
          # Cross-compilation build
          cargo tauri build --target ${{ matrix.target }}
        else
          # Native build
          cargo tauri build
        fi
      shell: bash
    - name: Prepare artifacts (Linux)
      if: matrix.os == 'ubuntu-latest'
      run: |
        mkdir -p artifacts
        cp src-tauri/target/${{ matrix.target }}/release/bundle/deb/*.deb artifacts/ || echo "No .deb files found"
        cp src-tauri/target/${{ matrix.target }}/release/bundle/appimage/*.AppImage artifacts/ || echo "No .AppImage files found"
        ls -la artifacts/
    - name: Prepare artifacts (Windows)
      if: matrix.os == 'windows-latest'
      run: |
        mkdir artifacts
        cp src-tauri/target/${{ matrix.target }}/release/bundle/msi/*.msi artifacts/ 2>/dev/null || echo "No .msi files found"
        ls artifacts/
      shell: bash
    - name: Prepare artifacts (macOS)
      if: matrix.os == 'macos-latest'
      run: |
        mkdir -p artifacts
        cp src-tauri/target/${{ matrix.target }}/release/bundle/dmg/*.dmg artifacts/ || echo "No .dmg files found"
        ls -la artifacts/
    - name: Upload artifacts to release (Linux .deb)
      if: matrix.os == 'ubuntu-latest'
      uses: actions/upload-release-asset@v1
      env:
        GITHUB_TOKEN: ${{ secrets.GITHUB_TOKEN }}
      with:
        upload_url: ${{ needs.create-release.outputs.upload_url }}
        asset_path: ./artifacts/stratosort_${{ steps.get_tag.outputs.tag }}_amd64.deb
        asset_name: StratoRust-${{ steps.get_tag.outputs.tag }}-linux-amd64.deb
        asset_content_type: application/vnd.debian.binary-package
      continue-on-error: true
    - name: Upload artifacts to release (Linux .AppImage)
      if: matrix.os == 'ubuntu-latest'
      uses: actions/upload-release-asset@v1
      env:
        GITHUB_TOKEN: ${{ secrets.GITHUB_TOKEN }}
      with:
        upload_url: ${{ needs.create-release.outputs.upload_url }}
        asset_path: ./artifacts/stratosort_${{ steps.get_tag.outputs.tag }}_amd64.AppImage
        asset_name: StratoRust-${{ steps.get_tag.outputs.tag }}-linux-x86_64.AppImage
        asset_content_type: application/octet-stream
      continue-on-error: true
    - name: Upload artifacts to release (Windows)
      if: matrix.os == 'windows-latest'
      uses: actions/upload-release-asset@v1
      env:
        GITHUB_TOKEN: ${{ secrets.GITHUB_TOKEN }}
      with:
        upload_url: ${{ needs.create-release.outputs.upload_url }}
        asset_path: ./artifacts/StratoRust_${{ steps.get_tag.outputs.tag }}_x64_en-US.msi
        asset_name: StratoRust-${{ steps.get_tag.outputs.tag }}-windows-x64.msi
        asset_content_type: application/x-msi
      continue-on-error: true
    - name: Upload artifacts to release (macOS)
      if: matrix.os == 'macos-latest'
      uses: actions/upload-release-asset@v1
      env:
        GITHUB_TOKEN: ${{ secrets.GITHUB_TOKEN }}
      with:
        upload_url: ${{ needs.create-release.outputs.upload_url }}
        asset_path: ./artifacts/StratoRust_${{ steps.get_tag.outputs.tag }}_${{ matrix.target }}.dmg
        asset_name: StratoRust-${{ steps.get_tag.outputs.tag }}-${{ matrix.name }}.dmg
        asset_content_type: application/x-apple-diskimage
      continue-on-error: true
  publish-release:
    name: Publish Release
    needs: [create-release, build-and-upload]
    runs-on: ubuntu-latest
    steps:
    - name: Publish Release
      uses: actions/github-script@v7
      with:
        github-token: ${{ secrets.GITHUB_TOKEN }}
        script: |
          const { owner, repo } = context.repo;
          const releaseId = '${{ needs.create-release.outputs.release_id }}';
          await github.rest.repos.updateRelease({
            owner,
            repo,
            release_id: releaseId,
            draft: false
          });
          console.log(`Published release ${releaseId}`);
  notify:
    name: Notify Release
    needs: [publish-release]
    runs-on: ubuntu-latest
    if: success()
    steps:
    - name: Get tag name
      id: get_tag
      run: |
        if [ "${{ github.event_name }}" = "workflow_dispatch" ]; then
          echo "tag=${{ github.event.inputs.tag }}" >> $GITHUB_OUTPUT
        else
          echo "tag=${GITHUB_REF#refs/tags/}" >> $GITHUB_OUTPUT
        fi
    - name: Notify Discord (if configured)
      if: env.DISCORD_WEBHOOK != ''
      env:
        DISCORD_WEBHOOK: ${{ secrets.DISCORD_WEBHOOK }}
      run: |
        curl -H "Content-Type: application/json" \
             -d "{\"content\":\"🚀 StratoRust ${{ steps.get_tag.outputs.tag }} has been released! Download it from GitHub Releases.\"}" \
             $DISCORD_WEBHOOK
    - name: Notify Slack (if configured)
      if: env.SLACK_WEBHOOK != ''
      env:
        SLACK_WEBHOOK: ${{ secrets.SLACK_WEBHOOK }}
      run: |
        curl -X POST -H 'Content-type: application/json' \
             --data "{\"text\":\"🚀 StratoRust ${{ steps.get_tag.outputs.tag }} has been released! Download it from GitHub Releases.\"}" \
             $SLACK_WEBHOOK
  update-homebrew:
    name: Update Homebrew Formula
    needs: [publish-release]
    runs-on: macos-latest
    if: success() && !contains(github.ref, 'alpha') && !contains(github.ref, 'beta') && !contains(github.ref, 'rc')
    steps:
    - name: Get tag name
      id: get_tag
      run: |
        if [ "${{ github.event_name }}" = "workflow_dispatch" ]; then
          echo "tag=${{ github.event.inputs.tag }}" >> $GITHUB_OUTPUT
        else
          echo "tag=${GITHUB_REF#refs/tags/}" >> $GITHUB_OUTPUT
        fi
    - name: Update Homebrew formula
      env:
        HOMEBREW_GITHUB_API_TOKEN: ${{ secrets.HOMEBREW_GITHUB_API_TOKEN }}
      run: |
        # This would update a Homebrew formula if we had one
        echo "Homebrew formula update would go here for stable release ${{ steps.get_tag.outputs.tag }}"
        # brew bump-formula-pr --strict stratosort --url=https://github.com/${{ github.repository }}/archive/${{ steps.get_tag.outputs.tag }}.tar.gzname: Test Suite (manual only)
on:
  workflow_dispatch:
env:
  CARGO_TERM_COLOR: always
  NODE_VERSION: '20'
  RUST_VERSION: 'stable'
jobs:
  frontend-tests:
    name: Frontend Tests
    runs-on: ${{ matrix.os }}
    strategy:
      fail-fast: false
      matrix:
        os: [ubuntu-latest, windows-latest, macos-latest]
    steps:
      - name: Checkout repository
        uses: actions/checkout@v4
      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: ${{ env.NODE_VERSION }}
          cache: 'npm'
      - name: Install dependencies
        run: npm ci
      - name: Run type checking
        run: npm run check
      - name: Run unit tests
        run: npm run test:ci
      - name: Run test coverage
        run: npm run test:coverage
      - name: Upload coverage reports
        uses: codecov/codecov-action@v3
        if: matrix.os == 'ubuntu-latest'
        with:
          files: ./coverage/lcov.info
          flags: frontend
          name: frontend-coverage
      - name: Upload test results
        uses: actions/upload-artifact@v3
        if: always()
        with:
          name: test-results-frontend-${{ matrix.os }}
          path: |
            test-results.json
            coverage/
  backend-tests:
    name: Backend Tests
    runs-on: ${{ matrix.os }}
    strategy:
      fail-fast: false
      matrix:
        os: [ubuntu-latest, windows-latest, macos-latest]
    steps:
      - name: Checkout repository
        uses: actions/checkout@v4
      - name: Setup Rust
        uses: dtolnay/rust-toolchain@stable
        with:
          toolchain: ${{ env.RUST_VERSION }}
      - name: Cache Rust dependencies
        uses: Swatinem/rust-cache@v2
        with:
          workspaces: src-tauri
      - name: Run backend tests
        working-directory: src-tauri
        run: |
          # Run lib tests first (fastest)
          cargo test --lib --no-fail-fast
          # Run integration tests separately
          cargo test --test '*' --no-default-features --features "test"
      - name: Run backend tests with coverage
        if: matrix.os == 'ubuntu-latest'
        working-directory: src-tauri
        run: |
          cargo install cargo-tarpaulin
          cargo tarpaulin --out Xml --output-dir ../coverage
      - name: Upload backend coverage
        uses: codecov/codecov-action@v3
        if: matrix.os == 'ubuntu-latest'
        with:
          files: ./coverage/cobertura.xml
          flags: backend
          name: backend-coverage
  integration-tests:
    name: Integration Tests
    runs-on: ${{ matrix.os }}
    strategy:
      fail-fast: false
      matrix:
        os: [ubuntu-latest, windows-latest, macos-latest]
    steps:
      - name: Checkout repository
        uses: actions/checkout@v4
      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: ${{ env.NODE_VERSION }}
          cache: 'npm'
      - name: Setup Rust
        uses: dtolnay/rust-toolchain@stable
        with:
          toolchain: ${{ env.RUST_VERSION }}
      - name: Cache Rust dependencies
        uses: Swatinem/rust-cache@v2
        with:
          workspaces: src-tauri
      - name: Install system dependencies (Ubuntu)
        if: matrix.os == 'ubuntu-latest'
        run: |
          sudo apt-get update
          sudo apt-get install -y \
            libgtk-3-dev \
            libwebkit2gtk-4.0-dev \
            libayatana-appindicator3-dev \
            librsvg2-dev \
            patchelf
      - name: Install frontend dependencies
        run: npm ci
      - name: Build application
        run: npm run build
      - name: Run integration tests
        run: npm run test:integration
      - name: Upload integration test results
        uses: actions/upload-artifact@v3
        if: always()
        with:
          name: integration-test-results-${{ matrix.os }}
          path: test-results/
  e2e-tests:
    name: E2E Tests
    runs-on: ${{ matrix.os }}
    strategy:
      fail-fast: false
      matrix:
        os: [ubuntu-latest, windows-latest, macos-latest]
        browser: [chromium, firefox, webkit]
        exclude:
          - os: windows-latest
            browser: webkit
    steps:
      - name: Checkout repository
        uses: actions/checkout@v4
      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: ${{ env.NODE_VERSION }}
          cache: 'npm'
      - name: Setup Rust
        uses: dtolnay/rust-toolchain@stable
        with:
          toolchain: ${{ env.RUST_VERSION }}
      - name: Cache Rust dependencies
        uses: Swatinem/rust-cache@v2
        with:
          workspaces: src-tauri
      - name: Install system dependencies (Ubuntu)
        if: matrix.os == 'ubuntu-latest'
        run: |
          sudo apt-get update
          sudo apt-get install -y \
            libgtk-3-dev \
            libwebkit2gtk-4.0-dev \
            libayatana-appindicator3-dev \
            librsvg2-dev \
            patchelf \
            xvfb
      - name: Install dependencies
        run: |
          npm ci
          npx playwright install --with-deps ${{ matrix.browser }}
      - name: Build application
        run: npm run build
      - name: Run E2E tests (Linux)
        if: matrix.os == 'ubuntu-latest'
        run: xvfb-run -a npm run test:e2e -- --project=${{ matrix.browser }}
      - name: Run E2E tests (Windows/macOS)
        if: matrix.os != 'ubuntu-latest'
        run: npm run test:e2e -- --project=${{ matrix.browser }}
      - name: Upload E2E test artifacts
        uses: actions/upload-artifact@v3
        if: failure()
        with:
          name: e2e-artifacts-${{ matrix.os }}-${{ matrix.browser }}
          path: |
            test-results/
            playwright-report/
            screenshots/
            videos/
  performance-tests:
    name: Performance Tests
    runs-on: ubuntu-latest
    steps:
      - name: Checkout repository
        uses: actions/checkout@v4
      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: ${{ env.NODE_VERSION }}
          cache: 'npm'
      - name: Install dependencies
        run: npm ci
      - name: Run performance tests
        run: npm run test:performance
      - name: Upload performance results
        uses: actions/upload-artifact@v3
        with:
          name: performance-results
          path: performance-results/
      - name: Comment on PR with performance results
        if: github.event_name == 'pull_request'
        uses: actions/github-script@v7
        with:
          script: |
            const fs = require('fs');
            const results = JSON.parse(fs.readFileSync('performance-results/summary.json', 'utf8'));
            const comment = `## Performance Test Results
            | Metric | Value | Budget | Status |
            |--------|-------|--------|--------|
            | File Scan (1000 files) | ${results.fileScan}ms | 500ms | ${results.fileScan <= 500 ? '✅' : '❌'} |
            | Analysis (100 files) | ${results.analysis}ms | 5000ms | ${results.analysis <= 5000 ? '✅' : '❌'} |
            | Search (10k items) | ${results.search}ms | 50ms | ${results.search <= 50 ? '✅' : '❌'} |
            | Memory Usage | ${results.memory}MB | 100MB | ${results.memory <= 100 ? '✅' : '❌'} |
            `;
            github.rest.issues.createComment({
              issue_number: context.issue.number,
              owner: context.repo.owner,
              repo: context.repo.repo,
              body: comment
            });
  accessibility-tests:
    name: Accessibility Tests
    runs-on: ubuntu-latest
    steps:
      - name: Checkout repository
        uses: actions/checkout@v4
      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: ${{ env.NODE_VERSION }}
          cache: 'npm'
      - name: Install dependencies
        run: npm ci
      - name: Build application
        run: npm run build
      - name: Run accessibility tests
        run: |
          npm install -D @axe-core/playwright
          npx playwright test --config=playwright.accessibility.config.ts
      - name: Upload accessibility report
        uses: actions/upload-artifact@v3
        if: always()
        with:
          name: accessibility-report
          path: accessibility-report/
  test-matrix-summary:
    name: Test Summary
    runs-on: ubuntu-latest
    needs: [frontend-tests, backend-tests, integration-tests, e2e-tests, performance-tests, accessibility-tests]
    if: always()
    steps:
      - name: Check test results
        run: |
          if [ "${{ needs.frontend-tests.result }}" != "success" ] || \
             [ "${{ needs.backend-tests.result }}" != "success" ] || \
             [ "${{ needs.integration-tests.result }}" != "success" ] || \
             [ "${{ needs.e2e-tests.result }}" != "success" ] || \
             [ "${{ needs.performance-tests.result }}" != "success" ] || \
             [ "${{ needs.accessibility-tests.result }}" != "success" ]; then
            echo "Some tests failed!"
            exit 1
          fi
          echo "All tests passed!"
      - name: Create test summary
        uses: actions/github-script@v7
        if: github.event_name == 'pull_request'
        with:
          script: |
            const summary = `## Test Results Summary
            | Test Suite | Status |
            |------------|--------|
            | Frontend Tests | ${{ needs.frontend-tests.result == 'success' && '✅ Passed' || '❌ Failed' }} |
            | Backend Tests | ${{ needs.backend-tests.result == 'success' && '✅ Passed' || '❌ Failed' }} |
            | Integration Tests | ${{ needs.integration-tests.result == 'success' && '✅ Passed' || '❌ Failed' }} |
            | E2E Tests | ${{ needs.e2e-tests.result == 'success' && '✅ Passed' || '❌ Failed' }} |
            | Performance Tests | ${{ needs.performance-tests.result == 'success' && '✅ Passed' || '❌ Failed' }} |
            | Accessibility Tests | ${{ needs.accessibility-tests.result == 'success' && '✅ Passed' || '❌ Failed' }} |
            View detailed results in the [Actions tab](https://github.com/${{ github.repository }}/actions/runs/${{ github.run_id }})
            `;
            github.rest.issues.createComment({
              issue_number: context.issue.number,
              owner: context.repo.owner,
              repo: context.repo.repo,
              body: summary
            });<!DOCTYPE html>
