                        {:else if page === 'discover'}
                            <ErrorBoundary fallback={false} let:captureError>
                                <DiscoverPage />
                            </ErrorBoundary>
                        {:else if page === 'analyze'}
                            <ErrorBoundary fallback={false} let:captureError>
