                        {/if}
                    </div>
                    <!-- ARIA live regions for accessibility announcements -->
                    <div aria-live="polite" class="sr-only" data-testid="live-region-polite"></div>
                    <div aria-live="assertive" class="sr-only" data-testid="live-region-assertive"></div>
